import json, ast
for nb_path in ['bengali-cyberbullying-lightweight-v4.ipynb', 'bengali-cyberbullying-transformer.ipynb']:
    nb = json.load(open(nb_path))
    for i, cell in enumerate(nb['cells']):
        if cell['cell_type'] == 'code':
            src = ''.join(cell['source'])
            try:
                ast.parse(src)
            except SyntaxError as e:
                raise RuntimeError(f'{nb_path} cell {i}: {e}')
    print(f'{nb_path}: all cells parse OK')
